function simulateRaceCondition() {
  console.log('Without ignore flag:');
  let currentData = null;

  // Request A starts (slow - resolves second)
  const requestA = () => { currentData = 'Stale data from Request A'; };
  // Request B starts (fast - resolves first)
  const requestB = () => { currentData = 'Fresh data from Request B'; };

  // B resolves first
  requestB();
  console.log('After B resolves: ' + currentData);
  // A resolves later, overwriting B!
  requestA();
  console.log('After A resolves: ' + currentData);
  console.log('Bug! Stale data displayed');
}

function simulateWithIgnoreFlag() {
  console.log('With ignore flag:');
  let currentData = null;
  let ignoreA = false;

  // User changes query, so we ignore A
  ignoreA = true;

  // Request B resolves
  currentData = 'Fresh data from Request B';
  console.log('After B resolves: ' + currentData);

  // Request A resolves but is ignored
  if (!ignoreA) {
    currentData = 'Stale data from Request A';
  } else {
    console.log('Request A ignored (stale)');
  }
  console.log('Final data: ' + currentData);
}

simulateRaceCondition();
console.log('---');
simulateWithIgnoreFlag();

