function createApiClient(config) {
  const requestInterceptors = [];
  const responseInterceptors = [];

  return {
    interceptors: {
      request: { use: (fn) => requestInterceptors.push(fn) },
      response: { use: (successFn, errorFn) => responseInterceptors.push({ successFn, errorFn }) }
    },
    get: (url) => {
      let reqConfig = { url: config.baseURL + url, headers: {} };

      // Run request interceptors
      requestInterceptors.forEach(fn => {
        reqConfig = fn(reqConfig);
      });
      console.log('Request: ' + reqConfig.url);
      console.log('Headers: ' + JSON.stringify(reqConfig.headers));

      // Simulate response
      let response = { status: 200, data: { message: 'Success' } };

      // Run response interceptors
      responseInterceptors.forEach(({ successFn }) => {
        response = successFn(response);
      });
      console.log('Response: ' + JSON.stringify(response.data));
      return response;
    }
  };
}

